function _validatePath(address[] calldata path) internal pure {
    uint256 pathLength = path.length;

    // Max 256 because of bits in directions
    if (pathLength > 256) {
        revert ErrPathTooLong();
    }
    if (pathLength <= 0) {
        revert ErrEmptyPath();
    }
}
